int   n   = chi('step_count');
float w   = chf('step_width');
float d   = chf('step_depth');
float h   = chf('step_height');
for (int i = 0; i < n; i++) {
    // bottom face 4 pts
    vector p0 = set(0,    i*h,       i*d);
    vector p1 = set(w,    i*h,       i*d);
    vector p2 = set(w,    i*h,  (i+1)*d);
    vector p3 = set(0,    i*h,  (i+1)*d);
    // top face 4 pts  (riser height)
    vector p4 = set(0,  (i+1)*h, (i+1)*d);
    vector p5 = set(w,  (i+1)*h, (i+1)*d);
    // tread prim
    int a0 = addpoint(0, p0);
    int a1 = addpoint(0, p1);
    int a2 = addpoint(0, p2);
    int a3 = addpoint(0, p3);
    addprim(0, 'poly', a0, a1, a2, a3);
    // riser prim
    int b0 = addpoint(0, p3);
    int b1 = addpoint(0, p2);
    int b2 = addpoint(0, p5);
    int b3 = addpoint(0, p4);
    addprim(0, 'poly', b0, b1, b2, b3);
}

